 27→export function ProfileWritingsTab({userId, headerComponent}: ProfileWritingsTabProps) {
 28→  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
 29→  const {session} = useAuth();
 30→  const token = session?.access_token ?? '';
 31→
 32→  const query = useInfiniteQuery({
 33→    queryKey: ['profileWritings', userId],
 34→    queryFn: ({pageParam}) =>
 35→      mobileApi.getUserJournals(token, userId, pageParam ?? null, PAGE_SIZE),
 36→    initialPageParam: null as string | null,
 37→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 38→  });
 39→
 40→  const posts = useMemo(
 41→    () => query.data?.pages.flatMap(page => page.data ?? []) ?? [],
 42→    [query.data?.pages],
 43→  );
 44→
 45→  return (
 46→    <FlatList
 47→      data={posts}
 48→      keyExtractor={item => item.id}
 49→      showsVerticalScrollIndicator={false}
 50→      contentContainerStyle={styles.list}
 51→      ListHeaderComponent={headerComponent}
 52→      onEndReachedThreshold={0.3}
 53→      onEndReached={() => {
 54→        if (query.hasNextPage && !query.isFetchingNextPage) {
 55→          query.fetchNextPage();
 56→        }
 57→      }}
 58→      ListEmptyComponent={
 59→        query.isLoading ? (
 60→          <View style={styles.skeletons}>
 61→            <PostCardSkeleton />
 62→            <PostCardSkeleton />
 63→            <PostCardSkeleton />
 64→          </View>
 65→        ) : (
 66→          <EmptyState
 67→            title="No writings yet"
 68→            subtitle="Journal posts will appear here."
 69→          />
 70→        )
 71→      }
 72→      ListFooterComponent={
 73→        query.isFetchingNextPage ? (
 74→          <View style={styles.footer}>
 75→            <PostCardSkeleton />
 76→          </View>
 77→        ) : null
 78→      }
 79→      renderItem={({item}) => {
 80→        const preview = extractPlainText(item.content).slice(0, 180);
 81→        const likeCount = resolveCount(item.like_count, item.likes_count);
 82→        const commentCount = resolveCount(item.comment_count, item.comments_count);
 83→        const bookmarkCount = resolveCount(item.bookmark_count);
 84→        const bannerImage = extractBannerImage(item.content, (item as any).images);
 85→
 86→        return (
 87→          <PostCard
 88→            title={item.title || 'Untitled Post'}
 89→            bodyPreview={preview || 'No preview text available.'}
 90→            authorName={item.users?.name || 'Unknown author'}
 91→            authorAvatar={item.users?.image_url}
 92→            authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
 93→            bannerImage={bannerImage}
 94→            postType={item.post_type ?? undefined}
 95→            likeCount={likeCount}
 96→            commentCount={commentCount}
 97→            bookmarkCount={bookmarkCount}
 98→            userReaction={item.user_reaction}
 99→            onPress={() =>
100→              navigation.navigate('PostDetail', {journalId: item.id})
101→            }
102→          />
103→        );
104→      }}
105→      ItemSeparatorComponent={() => <View style={styles.separator} />}
106→    />
107→  );
