 15→
 16→export function PrimaryButton({
 17→  label,
 18→  onPress,
 19→  loading,
 20→  disabled,
 21→  kind = 'primary',
 22→  icon,
 23→}: PrimaryButtonProps) {
 24→  const {colors, isDark} = useTheme();
 25→  const isDisabled = loading || disabled;
 26→
 27→  const bgColor =
 28→    kind === 'danger'
 29→      ? colors.danger
 30→      : kind === 'secondary'
 31→        ? 'transparent'
 32→        : isDark
 33→          ? colors.accentAmber
 34→          : colors.accentDark;
 35→
 36→  const textColor =
 37→    kind === 'danger'
 38→      ? '#FFFFFF'
 39→      : kind === 'secondary'
 40→        ? colors.textSecondary
 41→        : isDark
 42→          ? '#1A1612'
 43→          : colors.bgPrimary;
 44→
 45→  const borderColor =
 46→    kind === 'secondary' ? colors.borderLight : 'transparent';
 47→
 48→  return (
 49→    <Pressable
 50→      disabled={isDisabled}
 51→      onPress={onPress}
 52→      style={({pressed}) => [
 53→        styles.button,
 54→        {backgroundColor: bgColor, borderColor},
 55→        kind === 'secondary' && styles.secondary,
 56→        kind !== 'secondary' && shadows(colors).button,
 57→        isDisabled && styles.disabled,
 58→        pressed && !isDisabled && styles.pressed,
 59→      ]}>
 60→      {loading ? (
 61→        <ActivityIndicator color={textColor} size="small" />
 62→      ) : (
 63→        <View style={styles.inner}>
 64→          {icon}
 65→          <Text style={[styles.label, {color: textColor}]}>{label}</Text>
 66→        </View>
 67→      )}
 68→    </Pressable>
 69→  );
 70→}
